import{_ as e,a,b as d,c as o,d as r,e as l,f as i}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as n,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"إضافة قناة Discord","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/discord.md","filePath":"ar-SA/upload/discord.md","lastUpdated":1781962217000}'),p={name:"ar-SA/upload/discord.md"};function m(b,t,u,D,g,_){return n(),c("div",null,[...t[0]||(t[0]=[h('<h1 id="إضافة-قناة-discord" tabindex="-1">إضافة قناة Discord <a class="header-anchor" href="#إضافة-قناة-discord" aria-label="Permalink to &quot;إضافة قناة Discord&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-قبل-البدء؟" tabindex="-1">ما الذي تحتاجه قبل البدء؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-قبل-البدء؟" aria-label="Permalink to &quot;ما الذي تحتاجه قبل البدء؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>الغرض</th></tr></thead><tbody><tr><td>حساب Discord</td><td>لإنشاء خادم وقناة وتطبيق مطور.</td></tr><tr><td>خادم Discord</td><td>يجب أن ينضم البوت إلى خادم قبل أن يستطيع الوصول إلى قناة.</td></tr><tr><td>قناة نصية</td><td>سترسل الصور والملفات إلى هذه القناة.</td></tr><tr><td>Discord Developer Portal</td><td>لإنشاء application وبوت والحصول على <code>Bot Token</code>.</td></tr></tbody></table><h2 id="أين-تضيفها؟" tabindex="-1">أين تضيفها؟ <a class="header-anchor" href="#أين-تضيفها؟" aria-label="Permalink to &quot;أين تضيفها؟&quot;">​</a></h2><ol><li>افتح إعدادات النظام.</li><li>انتقل إلى إعدادات الرفع.</li><li>اضغط Add Channel في الزاوية العلوية اليمنى.</li><li>اختر <code>Discord</code>.</li></ol><h2 id="شرح-الحقول" tabindex="-1">شرح الحقول <a class="header-anchor" href="#شرح-الحقول" aria-label="Permalink to &quot;شرح الحقول&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحقل</th><th>وظيفته</th><th>مطلوب</th></tr></thead><tbody><tr><td>اسم القناة</td><td>اسم واضح للقناة، مثل &quot;Discord Primary&quot;.</td><td>نعم</td></tr><tr><td>Bot Token</td><td>رمز بوت Discord.</td><td>نعم</td></tr><tr><td>Channel ID</td><td>معرّف القناة النصية الهدف.</td><td>نعم</td></tr><tr><td>Proxy URL (اختياري)</td><td>استخدمه فقط إذا كان الوصول إلى Discord CDN غير مستقر. أدخل الرابط كاملًا مع <code>https://</code>.</td><td>لا</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="_1-أنشئ-خادم-discord-وقناة-نصية" tabindex="-1">1. أنشئ خادم Discord وقناة نصية <a class="header-anchor" href="#_1-أنشئ-خادم-discord-وقناة-نصية" aria-label="Permalink to &quot;1. أنشئ خادم Discord وقناة نصية&quot;">​</a></h3><ol><li>افتح Discord.</li><li>أنشئ خادمًا جديدًا، أو استخدم خادمًا تملكه.</li><li>أنشئ قناة نصية داخل ذلك الخادم.</li></ol><p><img src="'+e+'" alt="إنشاء خادم" loading="lazy"></p><h3 id="_2-أنشئ-بوتًا-في-discord-developer-portal" tabindex="-1">2. أنشئ بوتًا في Discord Developer Portal <a class="header-anchor" href="#_2-أنشئ-بوتًا-في-discord-developer-portal" aria-label="Permalink to &quot;2. أنشئ بوتًا في Discord Developer Portal&quot;">​</a></h3><ol><li>افتح Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>اضغط <code>New Application</code>.</li><li>أدخل اسم التطبيق وأنشئه.</li><li>افتح صفحة <code>Bot</code> من الشريط الجانبي.</li><li>أنشئ الرمز أو أعد ضبطه من صفحة <code>Bot</code>.</li><li>احفظ الرمز.</li></ol><p>هذا الرمز هو قيمة <code>Bot Token</code> التي تحتاج إلى إدخالها في ImgBed.</p><p><img src="'+a+'" alt="عرض رمز البوت" loading="lazy"></p><h3 id="_3-أنشئ-رابط-دعوة-oauth2-وثبّت-البوت" tabindex="-1">3. أنشئ رابط دعوة OAuth2 وثبّت البوت <a class="header-anchor" href="#_3-أنشئ-رابط-دعوة-oauth2-وثبّت-البوت" aria-label="Permalink to &quot;3. أنشئ رابط دعوة OAuth2 وثبّت البوت&quot;">​</a></h3><ol><li>افتح صفحة <code>OAuth2</code> من الشريط الجانبي.</li><li>ضمن scopes اختر <code>bot</code>.</li><li>في منطقة permissions فعّل الصلاحيات التالية:</li></ol><table tabindex="0"><thead><tr><th>الصلاحية</th><th>مطلوبة</th></tr></thead><tbody><tr><td>View Channels</td><td>نعم</td></tr><tr><td>Send Messages</td><td>نعم</td></tr><tr><td>Attach Files</td><td>نعم</td></tr><tr><td>Read Message History</td><td>نعم</td></tr></tbody></table><ol start="4"><li>في أسفل الصفحة تأكد أن integration type هو <code>Guild Install</code>.</li><li>انسخ الرابط الذي تم إنشاؤه.</li><li>افتح الرابط في المتصفح.</li><li>اختر الخادم الهدف.</li><li>أكمل مسار التفويض.</li></ol><p><img src="'+d+'" alt="اختيار صلاحيات البوت في OAuth2" loading="lazy"></p><p><img src="'+o+'" alt="دعوة البوت إلى القناة" loading="lazy"></p><h3 id="_4-فعّل-developer-mode-وانسخ-channel-id" tabindex="-1">4. فعّل Developer Mode وانسخ Channel ID <a class="header-anchor" href="#_4-فعّل-developer-mode-وانسخ-channel-id" aria-label="Permalink to &quot;4. فعّل Developer Mode وانسخ Channel ID&quot;">​</a></h3><ol><li>اضغط أيقونة الترس بجانب صورتك في أسفل يسار Discord.</li><li>افتح Advanced من الشريط الجانبي.</li><li>فعّل Developer Mode.</li><li>ارجع إلى القناة النصية الهدف.</li><li>اضغط بزر الفأرة الأيمن على اسم القناة.</li><li>اختر Copy Channel ID.</li></ol><p>الرقم المنسوخ هو قيمة <code>Channel ID</code> المطلوبة في ImgBed.</p><p><img src="'+r+'" alt="تفعيل developer mode" loading="lazy"></p><p><img src="'+l+'" alt="نسخ Channel ID" loading="lazy"></p><h3 id="_5-املأ-قناة-discord-في-imgbed" tabindex="-1">5. املأ قناة Discord في ImgBed <a class="header-anchor" href="#_5-املأ-قناة-discord-في-imgbed" aria-label="Permalink to &quot;5. املأ قناة Discord في ImgBed&quot;">​</a></h3><p>ارجع إلى نافذة إعداد القناة واملأ الحقول كما يلي:</p><table tabindex="0"><thead><tr><th>حقل الواجهة</th><th>القيمة</th></tr></thead><tbody><tr><td>Channel name</td><td>اسم مخصص للقناة، مثل <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>الرمز المحفوظ من صفحة <code>Bot</code> في Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>معرّف القناة الذي نسخته من Discord.</td></tr><tr><td>Proxy URL (اختياري)</td><td>عند الحاجة فقط، مثل <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>بعد الانتهاء اضغط Save.</p><p><img src="'+i+`" alt="إضافة إعداد قناة Discord" loading="lazy"></p><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الفحص</th><th>طريقة التحقق</th></tr></thead><tbody><tr><td>ظهور بطاقة القناة</td><td>بعد الحفظ يجب أن تظهر بطاقة قناة Discord في إعدادات الرفع.</td></tr><tr><td>إمكانية تفعيل القناة</td><td>يجب أن يبقى مفتاح Active مفعّلًا.</td></tr><tr><td>حفظ الإعداد</td><td>يجب أن تظهر في التفاصيل قيم Bot Token و Channel ID محفوظة.</td></tr><tr><td>نجاح الرفع</td><td>ارفع صورة تجريبية وتأكد من ظهورها في القناة النصية الهدف في Discord.</td></tr></tbody></table><h2 id="قائمة-تحقق-سريعة" tabindex="-1">قائمة تحقق سريعة <a class="header-anchor" href="#قائمة-تحقق-سريعة" aria-label="Permalink to &quot;قائمة تحقق سريعة&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>أنشئ خادم Discord</span></span>
<span class="line"><span>-&gt; أنشئ قناة نصية</span></span>
<span class="line"><span>-&gt; أنشئ بوتًا في Discord Developer Portal</span></span>
<span class="line"><span>-&gt; احفظ Bot Token من صفحة Bot</span></span>
<span class="line"><span>-&gt; في OAuth2 اختر bot و View Channels و Send Messages و Attach Files و Read Message History</span></span>
<span class="line"><span>-&gt; انسخ الرابط الناتج وفوّض البوت للخادم الهدف</span></span>
<span class="line"><span>-&gt; تأكد أن القناة النصية الهدف تمنح الصلاحيات نفسها</span></span>
<span class="line"><span>-&gt; فعّل Developer Mode</span></span>
<span class="line"><span>-&gt; اضغط بزر الفأرة الأيمن على القناة الهدف وانسخ Channel ID</span></span>
<span class="line"><span>-&gt; أدخل Bot Token و Channel ID في ImgBed</span></span>
<span class="line"><span>-&gt; احفظ وارفع صورة تجريبية</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const q=s(p,[["render",m]]);export{f as __pageData,q as default};
